using System.ComponentModel;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI.ChatCompletion;
using Microsoft.Extensions.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient("gpt-4o-mini-2024-07-18")
    .AsIChatClient();

var noteStore = new ResearchNotes();

var tools = new AITool[]
{
    AIFunctionFactory.Create(noteStore.TakeNote),
    AIFunctionFactory.Create(noteStore.GetNotes),
    AIFunctionFactory.Create(WebSearchTool.SearchAsync),
};

var agent = new ChatClientAgent(chatClient)
{
    Name = "ResearchAgent",
    Instructions = """
        You are a research agent. Given a topic, you must:
        1. Search the web for relevant information using the search_web tool
        2. Take notes on key findings using the take_note tool
        3. Search for additional details or related subtopics as needed
        4. Review your notes using the get_notes tool
        5. Provide a well-structured summary of your research findings

        Be thorough but focused. Take notes as you go to organize your findings.
        """,
    Tools = tools,
};

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var options = new ChatClientAgentInvokeOptions
{
    MaximumIterations = 10,
    Temperature = 0f,
};

var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
};

await foreach (var update in agent.InvokeStreamingAsync(history, options))
{
    Console.Write(update.Text);
}

Console.WriteLine("\n\n--- Research Notes ---");
foreach (var note in noteStore.Notes)
{
    Console.WriteLine($"\n## {note.Title}");
    Console.WriteLine(note.Content);
}

// --- Tool implementations ---

sealed class ResearchNotes
{
    private readonly List<Note> _notes = [];

    public IReadOnlyList<Note> Notes => _notes;

    [Description("Save a research note with a title and content. Use this to record key findings during research.")]
    public string TakeNote(
        [Description("Short descriptive title for the note")] string title,
        [Description("The note content with key findings")] string content)
    {
        _notes.Add(new Note(title, content));
        return $"Note saved: \"{title}\"";
    }

    [Description("Retrieve all saved research notes to review findings collected so far.")]
    public IReadOnlyList<Note> GetNotes() => _notes;
}

record Note(string Title, string Content);

static class WebSearchTool
{
    private static readonly HttpClient s_http = new()
    {
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
    };

    [Description("Search the web for information on a topic. Returns relevant search result snippets.")]
    public static async Task<string> SearchAsync(
        [Description("The search query string")] string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&srlimit=5&format=json";
            var json = await s_http.GetStringAsync(url);

            using var doc = JsonDocument.Parse(json);
            var results = doc.RootElement.GetProperty("query").GetProperty("search");

            var sb = new StringBuilder();
            sb.AppendLine($"Web search results for \"{query}\":");

            var i = 1;
            foreach (var result in results.EnumerateArray())
            {
                var title = result.GetProperty("title").GetString();
                var snippet = result.GetProperty("snippet").GetString()
                    ?.Replace("<span class=\"searchmatch\">", "")
                    .Replace("</span>", "");
                sb.AppendLine($"  {i}. {title} — {snippet}");
                i++;
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }
}

