using Microsoft.Extensions.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient("gpt-4o-mini-2024-07-18")
    .AsIChatClient();

var noteStore = new ResearchNotes();

var tools = new AITool[]
{
    AIFunctionFactory.Create(noteStore.TakeNote),
    AIFunctionFactory.Create(noteStore.GetNotes),
    AIFunctionFactory.Create(WebSearchTool.SearchAsync),
};

var agent = new ChatClientAgent(chatClient)
{
    Name = "ResearchAgent",
    Instructions = """
        You are a research agent. Given a topic, you must:
        1. Search the web for relevant information using the search_web tool
        2. Take notes on key findings using the take_note tool
        3. Search for additional details or related subtopics as needed
        4. Review your notes using the get_notes tool
        5. Provide a well-structured summary of your research findings

        Be thorough but focused. Take notes as you go to organize your findings.
        """,
    Tools = tools,
};

Console.Write("Enter a research topic: ");
